{
    "level": "A1",
    "intro": "Форми <strong>am / is / are</strong> допомагають говорити, <strong>хто ти</strong>, <strong>який ти</strong> і <strong>де хтось або щось є</strong>.",
    "rules": [
        {
            "label": "I am",
            "color": "emerald",
            "text": "З <strong>I</strong> використовуй тільки <strong>am</strong>.",
            "example": "I am tired. / I'm ready."
        },
        {
            "label": "He / She / It is",
            "color": "blue",
            "text": "З <strong>he / she / it</strong> використовуй <strong>is</strong>.",
            "example": "She is at home. / It's cold."
        },
        {
            "label": "You / We / They are",
            "color": "amber",
            "text": "З <strong>you / we / they</strong> використовуй <strong>are</strong>.",
            "example": "They are late. / We're friends."
        }
    ]
}

{
    "title": "1. Форми am / is / are",
    "intro": "Запам'ятай, яка форма йде з яким підметом.",
    "items": [
        {
            "label": "I",
            "title": "am",
            "subtitle": "I am happy. / I'm happy."
        },
        {
            "label": "He / She / It",
            "title": "is",
            "subtitle": "He is busy. / She's busy. / It's new."
        },
        {
            "label": "You / We / They",
            "title": "are",
            "subtitle": "You are right. / We're ready. / They're here."
        },
        {
            "label": "Short Forms",
            "title": "'m / 's / 're",
            "subtitle": "I'm, he's, she's, it's, we're, you're, they're."
        }
    ]
}

{
    "title": "2. Коли вживаємо to be",
    "sections": [
        {
            "label": "Хто це / що це",
            "color": "emerald",
            "description": "Використовуй <strong>to be</strong> з іменником, коли називаєш людину, річ або роль.",
            "examples": [
                {
                    "en": "I am a student.",
                    "ua": "Я студент."
                },
                {
                    "en": "She is my sister.",
                    "ua": "Вона моя сестра."
                }
            ]
        },
        {
            "label": "Який він / вона / вони",
            "color": "blue",
            "description": "Використовуй <strong>to be</strong> з прикметником для стану або ознаки.",
            "examples": [
                {
                    "en": "We are happy.",
                    "ua": "Ми щасливі."
                },
                {
                    "en": "He is tired.",
                    "ua": "Він втомлений."
                }
            ]
        },
        {
            "label": "Де хтось або щось є",
            "color": "amber",
            "description": "Використовуй <strong>to be</strong> з місцем.",
            "examples": [
                {
                    "en": "They are at home.",
                    "ua": "Вони вдома."
                },
                {
                    "en": "The keys are on the table.",
                    "ua": "Ключі на столі."
                }
            ]
        }
    ]
}

{
    "title": "3. Швидка таблиця",
    "intro": "Одна форма для кожної групи підметів.",
    "rows": [
        {
            "en": "I",
            "ua": "am",
            "note": "I am at school."
        },
        {
            "en": "He / She / It",
            "ua": "is",
            "note": "She is my friend."
        },
        {
            "en": "You",
            "ua": "are",
            "note": "You are late."
        },
        {
            "en": "We / They",
            "ua": "are",
            "note": "They are in the kitchen."
        }
    ],
    "warning": "📌 Не кажи <strong>I is</strong> або <strong>he are</strong>."
}

{
    "title": "4. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Пропуск to be у простому реченні.",
            "wrong": "❌ She happy.",
            "right": "✅ <span class=\"font-mono\">She is happy.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Неправильна форма після he / she / it.",
            "wrong": "❌ He are tired.",
            "right": "✅ <span class=\"font-mono\">He is tired.</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Форма to be перед звичайним дієсловом без потреби.",
            "wrong": "❌ I am play football.",
            "right": "✅ <span class=\"font-mono\">I play football.</span>"
        }
    ]
}

{
    "title": "5. Короткий підсумок",
    "items": [
        "З <strong>I</strong> використовуй <strong>am</strong>.",
        "З <strong>he / she / it</strong> використовуй <strong>is</strong>.",
        "З <strong>you / we / they</strong> використовуй <strong>are</strong>.",
        "Короткі форми: <strong>I'm, he's, she's, it's, we're, you're, they're</strong>.",
        "<strong>To be</strong> часто йде з іменником, прикметником або місцем."
    ]
}

